/* Lab 4 / Razor aliases → Open Design handoff classes */

.panel,
.glass.panel {
  background: var(--glass);
  backdrop-filter: var(--blur);
  -webkit-backdrop-filter: var(--blur);
  border: 1px solid var(--line);
