  padding: 10px 14px;
  font-size: 14px;
  outline: none;
  width: 100%;
  transition: all var(--transition);
}

.form-control:focus,
.field-input:focus {
  border-color: var(--acc);
  box-shadow: 0 0 0 3px rgba(138, 125, 255, 0.15);
}

.input-invalid,
.field-error-state { border-color: var(--danger) !important; }
.input-valid { border-color: var(--success) !important; }

.field-error,
.text-danger,
span.field-error { color: var(--danger); font-size: 12px; }

.crud-form { display: grid; gap: var(--space-md); max-width: 720px; }
.crud-form .field { display: flex; flex-direction: column; gap: 6px; }

.inline-form { display: inline; margin: 0; }
.link-btn {
