/* Page-specific styles from design/handoff */

/* Dashboard */
.hero-panel {
  display: flex; align-items: center; justify-content: space-between;
  gap: var(--space-lg);
  background: linear-gradient(130deg, rgba(138,125,255,0.18) 0%, rgba(63,208,255,0.08) 100%);
  margin-bottom: var(--space-lg);
}
.hero-eyebrow {
  font-size: 11px; font-weight: 700; color: var(--acc-2);
  text-transform: uppercase; letter-spacing: 0.12em;
  display: flex; align-items: center; gap: 7px; margin-bottom: 10px;
}
.hero-eyebrow::before { content: ''; display: inline-block; width: 24px; height: 2px; background: var(--acc-2); border-radius: 1px; }
.hero-title { font-size: 32px; font-weight: 800; letter-spacing: -0.025em; line-height: 1.15; margin-bottom: 8px; }
.hero-subtitle { color: var(--muted); font-size: 15px; max-width: 460px; }
.hero-date { font-size: 13px; color: var(--muted); margin-top: 6px; font-weight: 500; }
.hero-actions { display: flex; flex-direction: column; align-items: flex-end; gap: var(--space-sm); flex-shrink: 0; }
.section-gap { margin-bottom: var(--space-lg); }
.activity-panel { display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-md); }
.event-list { display: flex; flex-direction: column; gap: 8px; }
.event-row {
  display: flex; align-items: center; gap: 12px;
  padding: 10px 12px; border-radius: var(--radius-md);
  background: var(--glass); border: 1px solid var(--line);
  transition: all var(--transition);
}
.event-row:hover { border-color: var(--line-strong); }
.event-icon { width: 32px; height: 32px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 15px; flex-shrink: 0; }
.event-icon.out { background: rgba(138,125,255,0.15); }
.event-icon.in { background: rgba(63,208,255,0.12); }
.event-body { flex: 1; min-width: 0; }
.event-vehicle { font-size: 14px; font-weight: 600; }
.event-customer { font-size: 12px; color: var(--muted); }
.event-time { font-size: 13px; font-weight: 600; color: var(--muted); flex-shrink: 0; }
.event-link { font-size: 12px; color: var(--acc); flex-shrink: 0; }

/* Timeline */
.tl-toolbar { display: flex; align-items: center; gap: var(--space-md); margin-bottom: var(--space-md); flex-wrap: wrap; }
.tl-month-nav { display: flex; align-items: center; gap: var(--space-sm); }
.tl-month-title { font-size: 17px; font-weight: 700; min-width: 148px; text-align: center; }
.tl-legend { display: flex; align-items: center; gap: var(--space-md); flex-wrap: wrap; }
.tl-legend-item { display: flex; align-items: center; gap: 6px; font-size: 12px; color: var(--muted); }
.tl-legend-dot { width: 12px; height: 8px; border-radius: 3px; }
.timeline-outer { background: var(--glass); border: 1px solid var(--line); border-radius: var(--radius-lg); overflow: hidden; }
.timeline-scroll { overflow-x: auto; overflow-y: auto; max-height: calc(100vh - 270px); }
.tl-inner { min-width: max-content; }
.tl-header {
  display: flex; position: sticky; top: 0; z-index: 10;
  background: rgba(11,16,32,0.94); backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--line-strong);
}
.tl-side-col {
  width: 190px; min-width: 190px; padding: 10px 14px;
  font-size: 11px; font-weight: 700; color: var(--muted);
  text-transform: uppercase; letter-spacing: 0.08em;
  position: sticky; left: 0; z-index: 11;
  background: rgba(11,16,32,0.96); border-right: 1px solid var(--line-strong);
}
.tl-days { display: flex; }
.tl-day-header {
  width: 44px; min-width: 44px; text-align: center;
  padding: 5px 2px; font-size: 11px; color: var(--muted);
  border-right: 1px solid rgba(255,255,255,0.04);
}
.tl-day-header .dn { font-size: 14px; font-weight: 700; color: var(--txt); display: block; line-height: 1.2; }
.tl-day-header.weekend { background: rgba(255,255,255,0.025); }
.tl-day-header.today { background: rgba(63,208,255,0.07); }
.tl-day-header.today .dn { color: var(--acc-2); }
.tl-row { display: flex; align-items: stretch; border-bottom: 1px solid rgba(255,255,255,0.05); min-height: 60px; }
.tl-row-side {
  width: 190px; min-width: 190px; padding: 10px 14px;
  display: flex; flex-direction: column; justify-content: center; gap: 3px;
  position: sticky; left: 0; z-index: 5;
  background: rgba(11,16,32,0.92); border-right: 1px solid var(--line-strong);
}
.tl-veh-name { font-size: 13px; font-weight: 700; line-height: 1.2; }
.tl-veh-reg { font-size: 11px; font-weight: 700; color: var(--acc-2); letter-spacing: 0.08em; font-family: ui-monospace, monospace; }
.tl-veh-branch { font-size: 11px; color: var(--muted); }
.tl-track { position: relative; flex: 1; display: flex; align-items: center; height: 60px; }
.tl-cells-bg { position: absolute; inset: 0; display: flex; }
.tl-cell { width: 44px; min-width: 44px; height: 100%; border-right: 1px solid rgba(255,255,255,0.04); }
.tl-cell.weekend { background: rgba(255,255,255,0.02); }
.tl-cell.today { background: rgba(63,208,255,0.06); }
.tl-res {
  position: absolute; height: 30px; border-radius: var(--radius-sm);
  padding: 0 10px; display: flex; align-items: center;
  font-size: 11px; font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
  cursor: pointer; top: 50%; transform: translateY(-50%);
  left: calc((var(--s) - 1) * 44px + 2px);
  width: calc(var(--n) * 44px - 4px); z-index: 2; border: 1px solid transparent;
  text-decoration: none; color: inherit;
}
.tl-res:hover { z-index: 6; box-shadow: 0 4px 16px rgba(0,0,0,0.35); }
.tl-res.confirmed { background: rgba(63,208,255,0.17); color: var(--acc-2); border-color: rgba(63,208,255,0.35); }
.tl-res.active { background: rgba(138,125,255,0.2); color: var(--acc); border-color: rgba(138,125,255,0.4); }
.tl-res.completed { background: rgba(93,255,176,0.13); color: var(--success); border-color: rgba(93,255,176,0.28); }
.tl-res.draft { background: rgba(168,178,217,0.09); color: var(--muted); border-color: var(--line); }
.tl-res.cancelled { background: rgba(255,107,127,0.13); color: var(--danger); border-color: rgba(255,107,127,0.28); }

/* Dnevni plan */
.plan-header { display: flex; align-items: center; gap: var(--space-md); flex-wrap: wrap; margin-bottom: var(--space-lg); }
.plan-header h1 { font-size: 24px; font-weight: 800; flex: 1; }
.plan-cols { display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-lg); }
.plan-col-header { display: flex; align-items: center; gap: 10px; padding-bottom: var(--space-md); border-bottom: 1px solid var(--line); margin-bottom: var(--space-md); }
.col-icon { width: 36px; height: 36px; border-radius: var(--radius-md); display: flex; align-items: center; justify-content: center; font-size: 18px; }
.col-icon.povrat { background: rgba(63,208,255,0.12); border: 1px solid rgba(63,208,255,0.25); }
.col-icon.odlaz { background: rgba(138,125,255,0.12); border: 1px solid rgba(138,125,255,0.25); }
.ev-card { background: var(--glass); border: 1px solid var(--line); border-radius: var(--radius-md); padding: var(--space-md); margin-bottom: var(--space-sm); }
.ev-card.return .ev-time { color: var(--acc-2); }
.ev-vehicle { font-size: 16px; font-weight: 700; }
.ev-reg { font-size: 11px; font-weight: 700; color: var(--acc-2); font-family: ui-monospace, monospace; }
.ev-time { font-size: 18px; font-weight: 800; color: var(--acc); }

/* Fleet filter strip */
.filter-bar { display: flex; align-items: center; gap: var(--space-sm); flex-wrap: wrap; padding: var(--space-md) 0; }
.stats-strip { display: flex; gap: var(--space-lg); flex-wrap: wrap; padding-bottom: var(--space-md); font-size: 13px; color: var(--muted); }

/* Rezervacije table */
.tbl-id { font-family: ui-monospace, monospace; font-size: 12px; color: var(--muted); font-weight: 700; }
.tbl-reg { font-size: 11px; font-weight: 700; color: var(--acc-2); font-family: ui-monospace, monospace; }

/* Vehicle details */
.vehicle-hero {
  display: grid; grid-template-columns: 1fr 380px;
  background: var(--glass); border: 1px solid var(--line);
  border-radius: var(--radius-lg); overflow: hidden; margin-bottom: var(--space-lg);
}
.hero-visual {
  background: linear-gradient(130deg, rgba(138,125,255,0.14) 0%, rgba(63,208,255,0.07) 50%, transparent 100%);
  display: flex; align-items: center; justify-content: center; padding: var(--space-xl); min-height: 200px;
}
.hero-info { padding: var(--space-xl); border-left: 1px solid var(--line); display: flex; flex-direction: column; gap: 12px; justify-content: center; }
.hero-reg { font-size: 18px; font-weight: 700; color: var(--acc-2); font-family: ui-monospace, monospace; letter-spacing: 0.1em; }
.hero-price { font-size: 28px; font-weight: 800; color: var(--acc); }
.tabs-bar { display: flex; gap: 2px; border-bottom: 1px solid var(--line); margin-bottom: var(--space-lg); }
.tab-btn {
  padding: 10px 20px; font-size: 14px; font-weight: 600; color: var(--muted);
  border: none; background: transparent; cursor: pointer; font-family: inherit;
  border-bottom: 2px solid transparent; margin-bottom: -1px;
}
.tab-btn.active { color: var(--acc); border-bottom-color: var(--acc); background: rgba(138,125,255,0.07); }
.tab-panel { display: none; }
.tab-panel.active { display: block; }
.detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-lg); }
.detail-row { display: flex; justify-content: space-between; padding: 8px 0; border-bottom: 1px solid rgba(255,255,255,0.05); font-size: 14px; }
.detail-row span:first-child { color: var(--muted); }

.form-grid { display: grid; grid-template-columns: 1fr 320px; gap: var(--space-lg); align-items: start; }
.form-section-title {
  font-size: 13px; font-weight: 700; color: var(--muted);
  text-transform: uppercase; letter-spacing: 0.08em;
  margin-bottom: var(--space-md); padding-bottom: var(--space-sm);
  border-bottom: 1px solid var(--line);
}
.field-row { display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-md); }

@media (max-width: 980px) {
  .hero-panel { flex-direction: column; align-items: flex-start; }
  .hero-actions { align-items: flex-start; flex-direction: row; }
  .activity-panel { grid-template-columns: 1fr; }
  .vehicle-hero { grid-template-columns: 1fr; }
  .hero-info { border-left: none; border-top: 1px solid var(--line); }
  .form-grid { grid-template-columns: 1fr; }
  .plan-cols { grid-template-columns: 1fr; }
  .detail-grid { grid-template-columns: 1fr; }
}
@media (max-width: 640px) {
  .hero-title { font-size: 24px; }
  .field-row { grid-template-columns: 1fr; }
}

@model TimelineVm
@{
    ViewData["Title"] = "Timeline";
    ViewData["Breadcrumbs"] = BreadcrumbHelper.Build("Home", "Timeline");
    var monthInputValue = $"{Model.Month:yyyy-MM}-01";
    var today = DateOnly.FromDateTime(DateTime.UtcNow);
    var dayNames = new[] { "Ned", "Pon", "Uto", "Sri", "Čet", "Pet", "Sub" };
}

<div class="tl-toolbar rise-in">
    <div>
        <h1 style="font-size:22px;font-weight:800">Raspored flote</h1>
        <p style="font-size:13px;color:var(--muted);margin-top:2px">Pregled rezervacija po vozilu i danu</p>
    </div>
    <form method="get" class="tl-month-nav" style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
        <input type="hidden" name="q" value="@Model.SearchText" />
        <input type="hidden" name="vehicleType" value="@Model.VehicleType" />
        <input type="hidden" name="reservationStatus" value="@Model.ReservationStatus" />
        <input type="month" name="month" value="@($"{Model.Month:yyyy-MM}")" class="field-input" style="width:auto" onchange="this.form.submit()" />
        <button type="submit" class="btn btn-secondary btn-sm">Primijeni</button>
    </form>
    <div class="tl-legend">
        <div class="tl-legend-item"><div class="tl-legend-dot" style="background:rgba(63,208,255,0.55)"></div>Potvrđena</div>
        <div class="tl-legend-item"><div class="tl-legend-dot" style="background:rgba(138,125,255,0.65)"></div>Aktivna</div>
        <div class="tl-legend-item"><div class="tl-legend-dot" style="background:rgba(93,255,176,0.5)"></div>Završena</div>
        <div class="tl-legend-item"><div class="tl-legend-dot" style="background:rgba(168,178,217,0.3)"></div>Nacrt</div>
    </div>
    <a asp-controller="Reservation" asp-action="Create" class="btn btn-primary btn-sm" style="margin-left:auto">+ Nova rezervacija</a>
</div>

<form method="get" class="glass glass-sm rise-in" style="margin-bottom:var(--space-md);display:flex;gap:12px;flex-wrap:wrap;align-items:center">
    <input type="hidden" name="month" value="@monthInputValue" />
    <input type="text" name="q" value="@Model.SearchText" class="field-input" placeholder="Pretraga vozila…" style="max-width:220px" />
    <select name="vehicleType" class="field-select" style="width:auto">
        <option value="">Svi tipovi</option>
        @foreach (var t in Model.VehicleTypes)
        {
            <option value="@t" selected="@(Model.VehicleType == t.ToString())">@t</option>
        }
    </select>
    <select name="reservationStatus" class="field-select" style="width:auto">
        <option value="">Svi statusi</option>
        @foreach (var s in Model.ReservationStatuses)
        {
            <option value="@s" selected="@(Model.ReservationStatus == s.ToString())">@UiDisplayHelper.ReservationStatusLabel(s)</option>
        }
    </select>
    <button type="submit" class="btn btn-secondary btn-sm">Filtriraj</button>
</form>

<div class="timeline-outer rise-in">
    <div class="timeline-scroll">
        <div class="tl-inner">
            <div class="tl-header">
                <div class="tl-side-col">Vozilo</div>
                <div class="tl-days">
                    @foreach (var day in Model.Days)
                    {
                        var dow = (int)day.DayOfWeek;
                        var isWeekend = dow == 0 || dow == 6;
                        var isToday = day == today;
                        <div class="tl-day-header @(isWeekend ? "weekend" : "") @(isToday ? "today" : "")">
                            <span class="dn">@day.Day.ToString("00")</span>@dayNames[dow]
                        </div>
                    }
                </div>
            </div>
            @foreach (var row in Model.Rows)
            {
                var dayCount = Model.Days.Count;
                <div class="tl-row">
                    <div class="tl-row-side">
                        <div class="tl-veh-name">@row.Vehicle.Brand @row.Vehicle.Model</div>
                        <div class="tl-veh-reg">@row.Vehicle.RegistrationNumber</div>
                        @if (!string.IsNullOrEmpty(row.BranchName))
                        {
                            <div class="tl-veh-branch">@row.BranchName</div>
                        }
                    </div>
                    <div class="tl-track" style="min-width:@(dayCount * 44)px">
                        <div class="tl-cells-bg">
                            @foreach (var day in Model.Days)
                            {
                                var dow = (int)day.DayOfWeek;
                                <div class="tl-cell @(dow == 0 || dow == 6 ? "weekend" : "") @(day == today ? "today" : "")"></div>
                            }
                        </div>
                        @foreach (var bar in row.Bars)
                        {
                            var css = UiDisplayHelper.ReservationTimelineClass(bar.Reservation.Status);
                            var label = bar.Reservation.Customer is null ? $"#{bar.Reservation.Id}" : $"{bar.Reservation.Customer.FirstName} {bar.Reservation.Customer.LastName}";
                            <a asp-controller="Reservation" asp-action="Details" asp-route-id="@bar.Reservation.Id"
                               class="tl-res @css" style="--s:@bar.StartDay;--n:@bar.Span" title="@label">@label</a>
                        }
                    </div>
                </div>
            }
        </div>
    </div>
</div>

@model IReadOnlyList<Reservation>
@foreach (var item in Model)
{
    <tr>
        <td><span class="tbl-id">#@item.Id</span></td>
        <td>
            @if (item.Customer is not null)
            {
                <strong>@item.Customer.FirstName @item.Customer.LastName</strong>
            }
        </td>
        <td>
            @if (item.Vehicle is not null)
            {
                <span class="tbl-vehicle">@item.Vehicle.Brand @item.Vehicle.Model</span>
                <span class="tbl-reg">@item.Vehicle.RegistrationNumber</span>
            }
        </td>
        <td style="white-space:nowrap;color:var(--muted)">@item.StartDate.ToString("g")</td>
        <td style="white-space:nowrap;color:var(--muted)">@item.EndDate.ToString("g")</td>
        <td><partial name="_StatusChip" model="@(UiDisplayHelper.ReservationChipClass(item.Status), UiDisplayHelper.ReservationStatusLabel(item.Status))" /></td>
        <td class="tbl-price">@item.BasePrice.ToString("N2") €</td>
        <td class="actions">
            <a asp-action="Details" asp-route-id="@item.Id" class="btn btn-ghost btn-sm">Detalji</a>
            <a asp-action="Edit" asp-route-id="@item.Id" class="btn btn-ghost btn-sm">Uredi</a>
            <form asp-action="Delete" asp-route-id="@item.Id" method="post" class="inline-form" onsubmit="return confirm('Obrisati rezervaciju?');">
                @Html.AntiForgeryToken()
                <button type="submit" class="btn btn-ghost btn-sm" style="color:var(--danger)">Obriši</button>
            </form>
        </td>
    </tr>
}

